```javascript
// services/token.js
const Token = require('../models/token');

async function createToken(userId, token, expiresAt) {
  const existingToken = await Token.findOne({ userId });
  if (existingToken) {
    // If a token already exists, update its expiration time
    existingToken.expiresAt = expiresAt;
    await existingToken.save();
  } else {
    // Create a new token
    const newToken = new Token({
      userId,
      token,
      expiresAt,
      createdAt: new Date(),
    });
    await newToken.save();
  }
}

